mapper.sql:
SELECT SBJCT.SBJCT_ID , SBJCT.SBJCT_YR , SBJCT.SBJCT_SMSTR , ORG.ORG_ID , ORG.ORGNM , NVL(DEPT.DEPTNM, '-') AS DEPTNM , SBJCT.SBJCTNM , SBJCT.DVCLAS_NO , SBJCT.CRDTS , '-' AS SBJCT_CD-- 과목코드 , NVL(SBJCT_ADM.COPROF_USERNM, '-') AS COPROF_USERNM /* 공동교수 */ , NVL(SBJCT_ADM.ASSI_USERNM, '-') AS ASSI_USERNM /* 조교 */ , NVL(SBJCT_ADM.TUT_USERNM, '-') AS TUT_USERNM /* 튜터 */ , (CASE WHEN PLANDOC.LCTR_PLANDOC_ID IS NULL THEN 'N' ELSE 'Y' END) AS LSNPLANYN , ROW_NUMBER() OVER(ORDER BY SBJCT.SBJCT_YR DESC, SBJCT.SBJCT_SMSTR DESC, ORG.ORG_ID, SBJCT.SBJCT_ID) AS LINE_NO , COUNT(*) OVER() AS TOTAL_CNT FROM TB_LMS_SBJCT SBJCT JOIN TB_LMS_SMSTR_CHRT CHRT ON CHRT.SMSTR_CHRT_ID = SBJCT.SMSTR_CHRT_ID JOIN TB_LMS_ORG ORG ON ORG.ORG_ID = CHRT.ORG_ID JOIN TB_LMS_DEPT DEPT ON DEPT.DEPT_ID = SBJCT.DEPT_ID LEFT JOIN TB_LMS_LCTR_PLANDOC PLANDOC ON PLANDOC.SBJCT_ID = SBJCT.SBJCT_ID LEFT JOIN ( SELECT T1.SBJCT_ID , MAX(CASE WHEN T1.SBJCT_ADM_TYCD = 'PROF' THEN T2.USERNM END) AS PROF_USERNM , MAX(CASE WHEN T1.SBJCT_ADM_TYCD = 'COPROF' THEN T2.USERNM END) AS COPROF_USERNM , MAX(CASE WHEN T1.SBJCT_ADM_TYCD = 'ASSI' THEN T2.USERNM END) AS ASSI_USERNM , MAX(CASE WHEN T1.SBJCT_ADM_TYCD = 'TUT' THEN T2.USERNM END) AS TUT_USERNM FROM TB_LMS_SBJCT_ADM T1 JOIN TB_LMS_USER T2 ON T2.USER_ID = T1.USER_ID GROUP BY T1.SBJCT_ID ) SBJCT_ADM ON SBJCT_ADM.SBJCT_ID = SBJCT.SBJCT_ID WHERE 1=1 AND SBJCT.USEYN = 'Y' AND SBJCT.DELYN = 'N' AND SBJCT.PROF_ID = #{userId} AND SBJCT.SBJCT_YR = #{sbjctYr} AND TRIM(SBJCT.SBJCT_SMSTR) = TRIM(#{sbjctSmstr})
AND ORG.ORG_ID = #{orgId}
AND SBJCT.DEPT_ID = #{deptId}
AND SBJCT.SBJCT_ID = #{sbjctId}
ORDER BY SBJCT.SBJCT_YR DESC, SBJCT.SBJCT_SMSTR DESC, ORG.ORG_ID, SBJCT.SBJCT_ID

mapper.update:
/*
SQL ID : LctrPlandocDAO.lctrPlandocModify
설  명  : 강의계획서 수정
*/
UPDATE TB_LMS_LCTR_PLANDOC
SET
	MDFR_ID   = #{mdfrId}
	, MOD_DTTM = FN_DTTM()

		, CRCLMN_OTLN = #{crclmnOtln}


		, LCTR_GOAL = #{lctrGoal}


		, LCTR_OP_GDLN = #{lctrOpGdln}


		, LCTR_OP_PLAN = #{lctrOpPlan}


		, RLTD_SBJCT_CTS = #{rltdSbjctCts}


		, REMAKRS = #{remakrs}


		, PLYR_SHRTCT_KEY_PVSNYN = #{plyrShrtctKeyPvsnyn}


		, SCRPT_PVSNYN = #{scrptPvsnyn}


		, SBTTLS_PVSNYN = #{sbttlsPvsnyn}


		, PLYR_SPD_ADJST_PVSNYN = #{plyrSpdAdjstPvsnyn}

WHERE SBJCT_ID = #{sbjctId}

mapper.insert:
/*
	 SQL ID : LctrPlandocDAO.txtbkRegist
	 설  명  : 교재 등록
*/
INSERT INTO TB_LMS_TXTBK
(
	TXTBK_ID
	, SBJCT_ID
	, TXTBK_GBNCD
	, TXTBKNM
	, ISBN
	, WRTR
	, PBLSHR
)
VALUES
(
	 #{txtbkId}
	, #{sbjctId}
	, #{txtbkGbncd}
	, #{txtbknm}
	, #{isbn}
	, #{wrtr}
	, #{pblshr}
)

mapper.delete:
/*
	 SQL ID : LctrPlandocDAO.allTxtbkDelete
	 설  명  : 교재 전체 삭제
*/
DELETE FROM TB_LMS_TXTBK
WHERE SBJCT_ID = #{sbjctId}
